#include<bits/stdc++.h>
using namespace std;
long long a[100010],s[100010],dp[100010];
long long q[400010];
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        if(a[i]>m)
        {
            printf("-1");
            return 0;
        }
        s[i]=s[i-1]+a[i];
    }
    multiset<long long> S;
    long long l=1,r=0;
    for(long long i=1;i<=n;i++)
    {
        while(l<=r&&s[i]-s[q[l]]>m)
        {
            S.erase(dp[q[l]]+a[q[l+1]]);
            l++;
        }
        while(l<=r&&a[q[r]]<a[i])
        {
            S.erase(dp[q[r-1]]+a[q[r]]);
            r--;
        }
        if(l<=r)
        {
            S.insert(dp[q[r]]+a[i]);
        }
        q[++r]=i;
        long long L=0,R=i-1,best;
        while(L<=R)
        {
            long long mid=(L+R)/2;
            if(s[i]-s[mid]<=m)
            {
                R=mid-1;
                best=mid;
            }
            else
            {
                L=mid+1;
            }
        }
        dp[i]=dp[best]+a[q[l]];
        if(!S.empty())
        {
            dp[i]=min(dp[i],(*S.begin()));
        }
    }
    printf("%lld",dp[n]);
    return 0;
}
